patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 1ba548b6ff06..b4941260166c 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1153,6 +1153,7 @@ static bool MulWillOverflow(APInt &C0, APInt &C1, bool IsSigned) {
 // does not overflow.
 // Simplifies (X / C0) * C1 + (X % C0) * C2 to
 // (X / C0) * (C1 - C2 * C0) + X * C2
+
 Value *InstCombinerImpl::SimplifyAddWithRemainder(BinaryOperator &I) {
   Value *LHS = I.getOperand(0), *RHS = I.getOperand(1);
   Value *X, *MulOpV;
@@ -1162,14 +1163,19 @@ Value *InstCombinerImpl::SimplifyAddWithRemainder(BinaryOperator &I) {
   if (((MatchRem(LHS, X, C0, IsSigned) && MatchMul(RHS, MulOpV, MulOpC)) ||
        (MatchRem(RHS, X, C0, IsSigned) && MatchMul(LHS, MulOpV, MulOpC))) &&
       C0 == MulOpC) {
+    Value *DivOpV;
+    APInt DivOpC;
+    // Match MulOpV = X / C0
+    if (MatchDiv(MulOpV, DivOpV, DivOpC, IsSigned) && X == DivOpV &&
+        C0 == DivOpC)
+      return X;
+
     Value *RemOpV;
     APInt C1;
     bool Rem2IsSigned;
-    // Match MulOpC = RemOpV % C1
+    // Match MulOpV = RemOpV % C1
     if (MatchRem(MulOpV, RemOpV, C1, Rem2IsSigned) &&
         IsSigned == Rem2IsSigned) {
-      Value *DivOpV;
-      APInt DivOpC;
       // Match RemOpV = X / C0
       if (MatchDiv(RemOpV, DivOpV, DivOpC, IsSigned) && X == DivOpV &&
           C0 == DivOpC && !MulWillOverflow(C0, C1, IsSigned)) {
@@ -1193,14 +1199,50 @@ Value *InstCombinerImpl::SimplifyAddWithRemainder(BinaryOperator &I) {
   }
   Value *DivOpV;
   APInt DivOpC;
-  if (MatchRem(Rem, X, C0, IsSigned) &&
-      MatchDiv(Div, DivOpV, DivOpC, IsSigned) && X == DivOpV && C0 == DivOpC) {
+  bool Matched = MatchRem(Rem, X, C0, IsSigned) &&
+                 MatchDiv(Div, DivOpV, DivOpC, IsSigned) && X == DivOpV &&
+                 C0 == DivOpC;
+
+  if (!Matched) {
+    const APInt *ShC, *MaskC;
+    Value *DivX, *RemX;
+    unsigned BitWidth = I.getType()->getScalarSizeInBits();
+
+    if (match(Div, m_LShr(m_Value(DivX), m_APInt(ShC))) &&
+        match(Rem, m_And(m_Value(RemX), m_APInt(MaskC))) && DivX == RemX &&
+        ShC->ult(BitWidth)) {
+      unsigned ShAmt = ShC->getZExtValue();
+      if (MaskC->isMask(ShAmt)) {
+        X = DivX;
+        IsSigned = false;
+        C0 = APInt::getOneBitSet(BitWidth, ShAmt);
+        Matched = true;
+      }
+    } else if (match(Rem, m_LShr(m_Value(DivX), m_APInt(ShC))) &&
+               match(Div, m_And(m_Value(RemX), m_APInt(MaskC))) &&
+               DivX == RemX && ShC->ult(BitWidth)) {
+      unsigned ShAmt = ShC->getZExtValue();
+      if (MaskC->isMask(ShAmt)) {
+        std::swap(Div, Rem);
+        std::swap(C1, C2);
+        X = DivX;
+        IsSigned = false;
+        C0 = APInt::getOneBitSet(BitWidth, ShAmt);
+        Matched = true;
+      }
+    }
+  }
+
+  if (Matched) {
     APInt NewC = C1 - C2 * C0;
     if (!NewC.isZero() && !Rem->hasOneUse())
       return nullptr;
     if (!isGuaranteedNotToBeUndef(X, &AC, &I, &DT))
       return nullptr;
-    Value *MulXC2 = Builder.CreateMul(X, ConstantInt::get(X->getType(), C2));
+
+    Value *MulXC2 =
+        C2.isOne() ? X
+                   : Builder.CreateMul(X, ConstantInt::get(X->getType(), C2));
     if (NewC.isZero())
       return MulXC2;
     return Builder.CreateAdd(
@@ -1210,6 +1252,7 @@ Value *InstCombinerImpl::SimplifyAddWithRemainder(BinaryOperator &I) {
   return nullptr;
 }

+
 /// Fold
 ///   (1 << NBits) - 1
 /// Into:
